class Solution {
    public double minTime(int n, int k, int m, int[] time, double[] mul) {
        double[][] dp = new double[n + 1][m];
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < m; j++) {
                dp[i][j] = Double.MAX_VALUE;
            }
        }
        dp[0][0] = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < m; j++) {
                for (int l = 0; l < i && l <= k; l++) {
                    int nextStage = (j + Math.floor(Math.max(time[l - 1] * mul[j]) / 60)) % m;
                    dp[i][j] = Math.min(dp[i][j], dp[i - l][j] + Math.max(time[l - 1] * mul[j], 1.0));
                }
            }
        }
        double minTime = Double.MAX_VALUE;
        for (int j = 0; j < m; j++) {
            minTime = Math.min(minTime, dp[n][j]);
        }
        return minTime == Double.MAX_VALUE ? -1 : minTime;
    }
}
